<script setup>
import {ref} from 'vue'; const p=defineProps({id:String,label:String,hideLabel:Boolean,size:String,loading:Boolean,disabled:Boolean,value:[String,Object],placeholder:String,error:String,description:String,items:Array}); const options=['Apple','Banana','Cherry']; const open=ref(false), selected=ref(p.value||''); const id=(p.label||'select').toLowerCase().replace(/[^a-z0-9]+/g,'-')+'-listbox'; function key(e){if(['ArrowDown','Enter',' '].includes(e.key)){e.preventDefault();open.value=true}else if(e.key==='Escape')open.value=false} function choose(v){selected.value=v;open.value=false}
</script>
<template><div class="kumo-field"><label :for="id+'-trigger'" :class="p.hideLabel?'sr-only':''">{{p.label}}</label><button type="button" role="combobox" :id="id+'-trigger'" :aria-controls="id" :aria-expanded="open" aria-haspopup="listbox" :disabled="p.disabled||p.loading" :aria-busy="p.loading||undefined" :aria-invalid="p.error?true:undefined" @click="open=!open" @keydown="key" :class="['kumo-trigger',p.size||'base']"><span>{{selected||p.placeholder}}</span><svg aria-hidden="true" width="16" height="16" viewBox="0 0 16 16"><path fill="currentColor" d="m4 6 4 4 4-4z"/></svg></button><ul v-if="open" :id="id" role="listbox"><li v-for="o in options" role="option" :aria-selected="selected===o" tabindex="-1" @click="choose(o)">{{o}}</li></ul><p v-if="p.error" class="error">{{p.error}}</p><p v-else-if="p.description" class="description">{{p.description}}</p></div></template>
